		const scriptCbor = BROWSER_CONFIG.scripts.cosponsor.cbor;
		if (!scriptCbor) throw new Error("Cannot resolve script reference. Either:\n1. Use Kupo + Ogmios provider (recommended), OR\n2. Generate and add pre-computed script CBOR to BrowserConfig.ts\n\nSee SDK README for instructions.");
		const plutusScript = Core.PlutusV3Script.fromCbor(Core.HexBlob(scriptCbor));
		const script = Core.Script.newPlutusV3Script(plutusScript);
		const computedHash = script.hash();
		if (computedHash !== cosponsorHash) throw new Error(`Script hash mismatch!\nExpected: ${cosponsorHash}\nGot: ${computedHash}\n\nThe pre-computed CBOR in BrowserConfig.ts is outdated. Run 'bun run generate-script-cbor' in cosponsor-contracts to regenerate.`);
		const txInput = new Core.TransactionInput(Core.TransactionId(cosponsorUtxoRef.txHash), BigInt(cosponsorUtxoRef.outputIndex));
		const resolvedUtxos = await blaze.provider.resolveUnspentOutputs([txInput]);
		if (resolvedUtxos.length === 0) throw new Error(`Could not resolve reference UTxO: ${cosponsorUtxoRef.txHash}#${cosponsorUtxoRef.outputIndex}`);
		const resolvedUtxo = resolvedUtxos[0];
		const originalOutput = resolvedUtxo.output();
		const outputWithScript = new Core.TransactionOutput(originalOutput.address(), originalOutput.amount());
		const datum = originalOutput.datum();
		if (datum) outputWithScript.setDatum(datum);
		outputWithScript.setScriptRef(script);
		cosponsorReference = new Core.TransactionUnspentOutput(resolvedUtxo.input(), outputWithScript);
