	console.log("🔧 Building CosponsorDatum::Before from raw PlutusData");
	const datumFields = new PlutusList();
	datumFields.add(cosponsoredProposalProcedureData);
	const datumData = PlutusData.newConstrPlutusData(new ConstrPlutusData(0n, datumFields));
